<?php/** * Helper functions for AquaLuxe theme * * @package AquaLuxe */if (!defined('ABSPATH')) {    exit; // Exit if accessed directly.}/** * Get theme option * * @param string $option Option name. * @param mixed  $default Default value. * @return mixed */function aqualuxe_get_option($option, $default = '') {    return get_theme_mod($option, $default);}/** * Check if dark mode is enabled * * @return bool */function aqualuxe_is_dark_mode_enabled() {    return aqualuxe_get_option('aqualuxe_enable_dark_mode', true);}/** * Check if multilingual support is enabled * * @return bool */function aqualuxe_is_multilingual_enabled() {    return aqualuxe_get_option('aqualuxe_enable_multilingual', true);}/** * Get available languages * * @return array */function aqualuxe_get_languages() {    $languages = array(        'en' => array(            'name' => esc_html__('English', 'aqualuxe'),            'flag' => 'gb.svg',        ),        'fr' => array(            'name' => esc_html__('French', 'aqualuxe'),            'flag' => 'fr.svg',        ),        'de' => array(            'name' => esc_html__('German', 'aqualuxe'),            'flag' => 'de.svg',        ),        'es' => array(            'name' => esc_html__('Spanish', 'aqualuxe'),            'flag' => 'es.svg',        ),        'it' => array(            'name' => esc_html__('Italian', 'aqualuxe'),            'flag' => 'it.svg',        ),        'ja' => array(            'name' => esc_html__('Japanese', 'aqualuxe'),            'flag' => 'jp.svg',        ),        'zh' => array(            'name' => esc_html__('Chinese', 'aqualuxe'),            'flag' => 'cn.svg',        ),    );    return apply_filters('aqualuxe_languages', $languages);}